1	/**
2	 * AnthropicAdapter — direct Anthropic API integration via `@anthropic-ai/sdk`.
3	 *
4	 * Architecture (DECISIONS.md D6, docs/oracle/02 §"Shared architecture"):
5	 * - Calls Anthropic's REST API directly using Anthropic's official SDK.
6	 * - NO Vercel AI SDK and NO OpenRouter in this path.
7	 * - Authenticates via `ANTHROPIC_API_KEY` env var (the SDK auto-reads it).
8	 *
9	 * Caching strategy (round 1 — automatic prefix caching):
10	 * - Anthropic's prompt cache is opt-in per-block via `cache_control: { type:
11	 *   'ephemeral' }`. Round 1 marks the assembled stable system prompt as
12	 *   cacheable so repeated calls hit a read.
13	 * - Cache writes land in `usage.cache_creation_input_tokens`; cache reads in
14	 *   `usage.cache_read_input_tokens`. Both normalize into OracleUsage.
15	 * - Explicit-cache-breakpoint strategies (multiple markers across tools,
16	 *   schema, and semi-stable context) are a round-2 follow-up.
17	 *
18	 * Structured output:
19	 * - Uses Anthropic's native tool-calling mode with a forced single tool
20	 *   choice. The tool's `input_schema` is the standard JSON Schema produced
21	 *   from the caller's Zod schema. Anthropic enforces the schema on the
22	 *   model's tool call.
23	 *
24	 * Per docs/oracle/02-provider-native-ai-architecture.md → "Anthropic direct".
25	 */
26	
27	import Anthropic from '@anthropic-ai/sdk';
28	import type { Message, MessageCreateParamsNonStreaming } from '@anthropic-ai/sdk/resources/messages';
29	import type { MessageBatchIndividualResponse } from '@anthropic-ai/sdk/resources/messages/batches';
30	import type {
31	  OracleObjectResult,
32	  OracleTextResult,
33	  OracleUsage,
34	} from '../client/types';
35	import type { OracleModelRoute, ReasoningEffort } from '../routes';
36	import type {
37	  BatchResultItem,
38	  BatchStatus,
39	  GenerateObjectArgs,
40	  GenerateTextArgs,
41	  OracleProviderAdapter,
42	  RetrieveBatchArgs,
43	  RetrieveBatchResult,
44	  SubmitBatchArgs,
45	  SubmitBatchResult,
46	} from './types';
47	import {
48	  estimatePlanStableTokens,
49	  getCacheHints,
50	  markLastTextPartCacheable,
51	  normalizeMessageContentArray,
52	  pickAnthropicCacheTtl,
53	  shouldDisableCache,
54	} from './cache-utils';
55	import { flattenPlan, tryZodParse, zodToJsonSchema } from './vertex-gemini-adapter';
56	
57	export interface AnthropicAdapterOptions {
58	  /** API key. Defaults to env ANTHROPIC_API_KEY. */
59	  apiKey?: string;
60	  /** Mark the stable system prompt as cache_control: ephemeral. Default true. */
61	  enableSystemPromptCache?: boolean;
62	  /** Max output tokens for both generateText and generateObject. */
63	  defaultMaxTokens?: number;
64	}
65	
66	const DEFAULT_MAX_TOKENS = 4096;
67	const ANTHROPIC_SONNET_CACHE_MIN_TOKENS = 1024;
68	const ANTHROPIC_HAIKU_CACHE_MIN_TOKENS = 2048;
69	
70	export class AnthropicAdapter implements OracleProviderAdapter {
71	  readonly provider = 'anthropic' as const;
72	  private readonly client: Anthropic;
73	  private readonly enableSystemPromptCache: boolean;
74	  private readonly defaultMaxTokens: number;
75	
76	  constructor(opts: AnthropicAdapterOptions = {}) {
77	    const apiKey = opts.apiKey ?? process.env.ANTHROPIC_API_KEY;
78	    if (!apiKey) {
79	      throw new Error(
80	        'AnthropicAdapter: ANTHROPIC_API_KEY is not set. ' +
81	          'Set it in .env.local or pass {apiKey} explicitly.',
82	      );
83	    }
84	    this.client = new Anthropic({ apiKey });
85	    this.enableSystemPromptCache = opts.enableSystemPromptCache ?? true;
86	    this.defaultMaxTokens = opts.defaultMaxTokens ?? DEFAULT_MAX_TOKENS;
87	  }
88	
89	  async generateText(args: GenerateTextArgs): Promise<OracleTextResult> {
90	    const { plan, route, providerOptions } = args;
91	    const { systemPrompt, userMessage } = flattenPlan(plan);
92	    const callStartedAt = Date.now();
93	
94	    const ttl = pickAnthropicCacheTtl(plan.taskType, providerOptions);
95	    const messages = this.buildMessages(plan, userMessage, providerOptions, ttl);
96	    const thinking = thinkingParam(route.reasoningEffort, this.defaultMaxTokens);
97	    const response = await this.client.messages.create({
98	      model: route.modelId,
99	      max_tokens: this.defaultMaxTokens,
100	      // Anthropic requires temperature=1 when thinking is enabled.
101	      temperature: thinking
102	        ? 1
103	        : (typeof providerOptions?.temperature === 'number'
104	          ? providerOptions.temperature
105	          : undefined),
106	      system: this.buildSystem(plan, systemPrompt, providerOptions, ttl),
107	      messages,
108	      ...(thinking ? { thinking } : {}),
109	    });
110	    const latencyMs = Date.now() - callStartedAt;
111	    return {
112	      text: this.extractText(response),
113	      usage: this.normalizeUsage(response, latencyMs),
114	      rawResponse: response,
115	    };
116	  }
117	
118	  async generateObject<TSchema, TOutput>(
119	    args: GenerateObjectArgs<TSchema>,
120	  ): Promise<OracleObjectResult<TOutput>> {
121	    const { plan, route, schema, providerOptions } = args;
122	    const { systemPrompt, userMessage } = flattenPlan(plan);
123	    const jsonSchema = zodToJsonSchema(schema) as Record<string, unknown>;
124	    const callStartedAt = Date.now();
125	    const ttl = pickAnthropicCacheTtl(plan.taskType, providerOptions);
126	
127	    // Force a single tool call. The tool's input_schema is the structured
128	    // output contract; Anthropic enforces it on the model.
129	    const TOOL_NAME = 'output_structured';
130	    const thinking = thinkingParam(route.reasoningEffort, this.defaultMaxTokens);
131	    const response = await this.client.messages.create({
132	      model: route.modelId,
133	      max_tokens: this.defaultMaxTokens,
134	      // Anthropic forbids temperature != 1 when thinking is enabled.
135	      temperature: thinking ? 1 : 0.1,
136	      system: this.buildSystem(plan, systemPrompt, providerOptions, ttl),
137	      messages: this.buildMessages(plan, userMessage, providerOptions, ttl),
138	      tools: [
139	        {
140	          name: TOOL_NAME,
141	          description:
142	            'Return the structured output. You MUST use this tool exactly once and never reply in plain text.',
143	          input_schema: jsonSchema as Anthropic.Tool.InputSchema,
144	        },
145	      ],
146	      tool_choice: { type: 'tool', name: TOOL_NAME },
147	      ...(thinking ? { thinking } : {}),
148	    });
149	    const latencyMs = Date.now() - callStartedAt;
150	    const toolUse = response.content.find((b) => b.type === 'tool_use');
151	    if (!toolUse || toolUse.type !== 'tool_use') {
152	      throw new Error(
153	        `AnthropicAdapter.generateObject: response contained no tool_use block. ` +
154	          `stop_reason=${response.stop_reason}`,
155	      );
156	    }
157	    const validated = tryZodParse<TOutput>(schema, toolUse.input);
158	    return {
159	      object: (validated ?? toolUse.input) as TOutput,
160	      usage: this.normalizeUsage(response, latencyMs),
161	      rawResponse: response,
162	    };
163	  }
164	
165	  /**
166	   * Submit a batch of requests to Anthropic's Message Batches API. Each
167	   * request reuses the same per-call shape as generateText / generateObject
168	   * but is bundled into a single `messages.batches.create` call. 50% off
169	   * sync pricing with a 24-hour SLA.
170	   *
171	   * When `jsonSchema` is provided, the batch is treated as generateObject:
172	   * each request gets a forced single tool call whose `input_schema` is the
173	   * structured-output contract (mirrors generateObject above).
174	   *
175	   * The batch ID alone is sufficient to retrieve results later, so
176	   * providerMetadata is an empty object (see types.ts SubmitBatchResult).
177	   */
178	  async submitBatch(args: SubmitBatchArgs): Promise<SubmitBatchResult> {
179	    const { route, requests, jsonSchema } = args;
180	    const thinking = thinkingParam(route.reasoningEffort, this.defaultMaxTokens);
181	    const TOOL_NAME = 'output_structured';
182	    const structuredTool = jsonSchema
183	      ? {
184	          name: TOOL_NAME,
185	          description:
186	            'Return the structured output. You MUST use this tool exactly once and never reply in plain text.',
187	          input_schema: jsonSchema as Anthropic.Tool.InputSchema,
188	        }
189	      : undefined;
190	
191	    const sdkRequests = requests.map((req) => {
192	      const { systemPrompt, userMessage } = flattenPlan(req.plan);
193	      const providerOptions = req.providerOptions;
194	      const params: MessageCreateParamsNonStreaming = {
195	        model: route.modelId,
196	        max_tokens: this.defaultMaxTokens,
197	        temperature: thinking
198	          ? 1
199	          : structuredTool
200	            ? 0.1
201	            : (typeof providerOptions?.temperature === 'number'
202	              ? providerOptions.temperature
203	              : undefined) as number | undefined,
204	        system: systemPrompt,
205	        messages: [{ role: 'user', content: userMessage }],
206	        ...(structuredTool
207	          ? {
208	              tools: [structuredTool],
209	              tool_choice: { type: 'tool', name: TOOL_NAME } as const,
210	            }
211	          : {}),
212	        ...(thinking ? { thinking } : {}),
213	      };
214	      return { custom_id: req.customId, params };
215	    });
216	
217	    const batch = await this.client.messages.batches.create({ requests: sdkRequests });
218	    return {
219	      providerBatchId: batch.id,
220	      providerMetadata: {},
221	    };
222	  }
223	
224	  /**
225	   * Poll status and, when terminal, stream the per-request results JSONL.
226	   * Each line carries the caller's `custom_id` so results map back to the
227	   * originating BatchRequest.
228	   *
229	   * Anthropic processing_status:
230	   *   in_progress | canceling → still running ('in_progress')
231	   *   ended                   → terminal; iterate results to build items
232	   *
233	   * Per-item `result.type`:
234	   *   succeeded → success; pull text or tool_use block
235	   *   errored   → failure with error.message
236	   *   canceled  → failure 'request canceled'
237	   *   expired   → failure 'request expired'
238	   */
239	  async retrieveBatch(args: RetrieveBatchArgs): Promise<RetrieveBatchResult> {
240	    const { providerBatchId } = args;
241	    const batch = await this.client.messages.batches.retrieve(providerBatchId);
242	    const counts = batch.request_counts;
243	    const requestCount =
244	      counts.processing + counts.succeeded + counts.errored + counts.canceled + counts.expired;
245	    const completedCount = counts.succeeded;
246	    const failedCount = counts.errored + counts.canceled + counts.expired;
247	
248	    if (batch.processing_status !== 'ended') {
249	      return {
250	        status: 'in_progress' as BatchStatus,
251	        requestCount,
252	        completedCount,
253	        failedCount,
254	      };
255	    }
256	
257	    const results: BatchResultItem[] = [];
258	    const stream = await this.client.messages.batches.results(providerBatchId);
259	    for await (const entry of stream as AsyncIterable<MessageBatchIndividualResponse>) {
260	      results.push(this.normalizeBatchResultItem(entry));
261	    }
262	
263	    return {
264	      status: 'completed',
265	      results,
266	      requestCount,
267	      completedCount,
268	      failedCount,
269	    };
270	  }
271	
272	  private normalizeBatchResultItem(entry: MessageBatchIndividualResponse): BatchResultItem {
273	    const customId = entry.custom_id;
274	    const result = entry.result;
275	    if (result.type === 'errored') {
276	      return {
277	        customId,
278	        success: false,
279	        error: result.error?.error?.message ?? 'errored',
280	      };
281	    }
282	    if (result.type === 'canceled') {
283	      return { customId, success: false, error: 'request canceled' };
284	    }
285	    if (result.type === 'expired') {
286	      return { customId, success: false, error: 'request expired' };
287	    }
288	    // succeeded
289	    const message = result.message;
290	    const usage = this.normalizeUsage(message, 0);
291	    const toolUse = message.content.find((b) => b.type === 'tool_use');
292	    if (toolUse && toolUse.type === 'tool_use') {
293	      return { customId, success: true, output: toolUse.input, usage };
294	    }
295	    return { customId, success: true, text: this.extractText(message), usage };
296	  }
297	
298	  /**
299	   * Build the system field. When caching is enabled and the system prompt is
300	   * non-empty, use the array-of-blocks form so we can attach
301	   * cache_control: { type: 'ephemeral' }. Otherwise pass the plain string.
302	   */
303	  private buildSystem(
304	    plan: GenerateTextArgs['plan'],
305	    systemPrompt: string,
306	    providerOptions?: Record<string, unknown>,
307	    ttl?: '5m' | '1h',
308	  ): string | Anthropic.TextBlockParam[] {
309	    if (!this.enableSystemPromptCache || systemPrompt.length === 0 || shouldDisableCache(providerOptions)) {
310	      return systemPrompt;
311	    }
312	    const minTokens = anthropicCacheMinTokens(plan.routeId);
313	    const stableTokens = estimatePlanStableTokens(plan);
314	    if (stableTokens < minTokens) return systemPrompt;
315	    return [
316	      {
317	        type: 'text',
318	        text: systemPrompt,
319	        cache_control: ttl ? { type: 'ephemeral', ttl } : { type: 'ephemeral' },
320	      },
321	    ];
322	  }
323	
324	  /**
325	   * Build the messages array. If the caller passed a multi-turn `messages`
326	   * override via providerOptions (chat route does this for R8 multi-turn),
327	   * pass it through; otherwise wrap the flattened user message in a single
328	   * user turn.
329	   */
330	  private buildMessages(
331	    plan: GenerateTextArgs['plan'],
332	    userMessage: string,
333	    providerOptions?: Record<string, unknown>,
334	    ttl?: '5m' | '1h',
335	  ): Anthropic.MessageParam[] {
336	    const override = providerOptions?.messages as
337	      | Array<{ role: string; content: unknown }>
338	      | undefined;
339	    if (Array.isArray(override) && override.length > 0) {
340	      const filtered = override
341	        .filter((m) => m.role === 'user' || m.role === 'assistant')
342	        .map((m) => ({
343	          role: m.role as 'user' | 'assistant',
344	          content: normalizeMessageContentArray(m.content) as unknown as Anthropic.MessageParam['content'],
345	        }));
346	      if (shouldDisableCache(providerOptions)) return filtered;
347	
348	      const hint = getCacheHints(providerOptions);
349	      const minTokens = anthropicCacheMinTokens(plan.routeId);
350	      const prefixText = filtered
351	        .slice(0, -1)
352	        .map((m) =>
353	          Array.isArray(m.content)
354	            ? m.content
355	                .map((part) => ('text' in part ? String(part.text ?? '') : ''))
356	                .join('\n')
357	            : '',
358	        )
359	        .join('\n');
360	      if (
361	        filtered.length > 1 &&
362	        (estimateText(prefixText) >= minTokens || hint?.preferExplicitCache)
363	      ) {
364	        const target = filtered[filtered.length - 2]!;
365	        target.content = markLastTextPartCacheable(
366	          target.content as unknown as Array<Record<string, unknown>>,
367	          ttl,
368	        ) as unknown as Anthropic.MessageParam['content'];
369	      }
370	      return filtered;
371	    }
372	    return [{ role: 'user', content: userMessage }];
373	  }
374	
375	  /** Extract concatenated text from response content blocks (ignores tool_use). */
376	  private extractText(response: Message): string {
377	    const parts: string[] = [];
378	    for (const block of response.content) {
379	      if (block.type === 'text') parts.push(block.text);
380	    }
381	    return parts.join('');
382	  }
383	
384	  /**
385	   * Normalize Anthropic usage into OracleUsage.
386	   *   - input_tokens                 -> inputTokens
387	   *   - output_tokens                -> outputTokens
388	   *   - cache_read_input_tokens      -> cachedInputTokens
389	   *   - cache_creation_input_tokens  -> cacheWriteTokens
390	   */
391	  private normalizeUsage(response: Message, latencyMs: number): OracleUsage {
392	    const u = response.usage;
393	    return {
394	      inputTokens: u.input_tokens,
395	      outputTokens: u.output_tokens,
396	      cachedInputTokens: u.cache_read_input_tokens ?? undefined,
397	      cacheWriteTokens: u.cache_creation_input_tokens ?? undefined,
398	      latencyMs,
399	      providerRequestId: response.id,
400	      rawUsageJson: u,
401	    };
402	  }
403	}
404	
405	function anthropicCacheMinTokens(routeId: string): number {
406	  return routeId.includes('haiku')
407	    ? ANTHROPIC_HAIKU_CACHE_MIN_TOKENS
408	    : ANTHROPIC_SONNET_CACHE_MIN_TOKENS;
409	}
410	
411	function estimateText(text: string): number {
412	  return Math.ceil(text.length / 4);
413	}
414	
415	/**
416	 * Build Anthropic's `thinking` request parameter from a unified effort enum.
417	 * Returns undefined when no thinking should be requested (off, undefined, or
418	 * when budget would exceed the model's max_tokens). The budget MUST be less
419	 * than max_tokens — Anthropic rejects the request otherwise.
420	 */
421	function thinkingParam(
422	  effort: ReasoningEffort | undefined,
423	  maxTokens: number,
424	): { type: 'enabled'; budget_tokens: number } | undefined {
425	  if (!effort || effort === 'off') return undefined;
426	  const targetBudget = effort === 'low' ? 2048 : effort === 'medium' ? 8192 : 24000;
427	  // Clamp so budget < max_tokens. Reserve at least 512 tokens for the answer.
428	  const budget = Math.max(1024, Math.min(targetBudget, maxTokens - 512));
429	  if (budget < 1024) return undefined;   // model can't fit even a low budget
430	  return { type: 'enabled', budget_tokens: budget };
431	}
