52	  OracleObjectResult,
53	  OraclePromptPlan,
54	  OracleTextResult,
55	  OracleUsage,
56	} from '../client/types';
57	import type { OracleModelRoute, ReasoningEffort } from '../routes';
58	import type {
59	  BatchResultItem,
60	  BatchStatus,
61	  GenerateObjectArgs,
62	  GenerateTextArgs,
63	  OracleProviderAdapter,
64	  RetrieveBatchArgs,
