80	
81	export interface VertexGeminiAdapterOptions {
82	  /** GCP project ID. Defaults to env GOOGLE_CLOUD_PROJECT. */
83	  project?: string;
84	  /** Vertex region. Defaults to env GOOGLE_CLOUD_LOCATION or 'us-central1'. */
85	  location?: string;
