474	  private async prepareExplicitFileCache(
475	    plan: OraclePromptPlan,
476	    modelId: string,
477	    systemPrompt: string,
478	    providerOptions?: Record<string, unknown>,
479	  ): Promise<{
480	    name: string;
481	    dynamicInput: string;
482	    lifecycleHandle?: CacheLifecycleHandle;
483	  } | null> {
484	    const hints = getCacheHints(providerOptions);
485	    const fileSource = hints?.vertexFileCacheSource;
486	    if (!fileSource || hints?.preferExplicitCache !== true) return null;
487	
488	    const { dynamicInput } = splitPlanForCaching(plan);
489	    const gcsUpload = await this.ensureVertexCacheFileUri(fileSource);
490	    if (!gcsUpload?.fileUri) return null;
491	
492	    const explicitCache = await this.getOrCreateExplicitCache({
493	      modelId,
494	      systemInstruction: systemPrompt,
495	      contents: [
496	        {
497	          role: 'user',
498	          parts: [
499	            {
500	              fileData: {
501	                fileUri: gcsUpload.fileUri,
502	                mimeType: fileSource.mimeType,
503	              },
504	            },
505	          ],
506	        },
507	      ],
508	      ttlSeconds: pickVertexCacheTtlSeconds(plan.taskType, providerOptions),
509	      cacheKey: hashCacheKey([
510	        modelId,
511	        plan.metadata.stablePrefixHash,
512	        fileSource.sourceHash ?? fileSource.gcsUri ?? fileSource.localPath,
513	        'file-backed',
514	      ]),
515	      sourceHash: fileSource.sourceHash ??
516	        hashCacheKey([plan.metadata.stablePrefixHash, fileSource.gcsUri ?? fileSource.localPath, 'file-backed']),
517	      sourceTokenEstimate: estimatePlanStableTokens(plan),
518	      sourceDescription: hints?.sourceDescription ?? `${plan.taskType} file-backed cache`,
519	      expectedReuseCount: Math.max(1, hints?.expectedReuseCount ?? 1),
520	      latestPlannedReuseStep: hints?.latestPlannedReuseStep ?? plan.taskType,
521	      cleanupOwner: hints?.cleanupOwner,
522	      createdByJobRunId: hints?.createdByJobRunId,
523	      persistRecord: hints?.persistProviderCacheRecord === true,
524	      providerMetadataJson: gcsUpload.objectName
525	        ? {
526	            uploadedGcsUri: gcsUpload.fileUri,
527	            uploadedObjectName: gcsUpload.objectName,
528	            mimeType: fileSource.mimeType,
529	          }
530	        : undefined,
531	    });
532	    if (!explicitCache) return null;
533	    return {
534	      name: explicitCache.name,
535	      dynamicInput,
536	      lifecycleHandle: explicitCache.lifecycleHandle,
537	    };
538	  }
