573	  private async getPersistedExplicitCache(input: {
574	    cacheKey: string;
575	    sourceHash: string;
576	    systemInstruction?: string;
577	  }): Promise<{ name: string; lifecycleHandle?: CacheLifecycleHandle } | null> {
578	    const db = getDirectDb();
579	    const [row] = await db
580	      .select({
581	        id: providerCachedContent.id,
582	        providerResourceName: providerCachedContent.providerResourceName,
583	        hardExpirationAt: providerCachedContent.hardExpirationAt,
584	      })
585	      .from(providerCachedContent)
586	      .where(
587	        and(
588	          eq(providerCachedContent.provider, 'vertex'),
589	          eq(providerCachedContent.status, 'active'),
590	          eq(providerCachedContent.sourceHash, input.sourceHash),
591	          isNotNull(providerCachedContent.providerResourceName),
592	          gt(providerCachedContent.hardExpirationAt, new Date()),
593	        ),
594	      )
595	      .orderBy(desc(providerCachedContent.createdAt))
596	      .limit(1);
597	
598	    if (!row?.providerResourceName) return null;
599	
600	    try {
601	      await this.client.caches.get({ name: row.providerResourceName });
602	      const expiresAtMs = new Date(row.hardExpirationAt).getTime();
603	      this.explicitCacheByKey.set(input.cacheKey, {
604	        name: row.providerResourceName,
605	        expiresAtMs,
606	        includesSystemInstruction: !!input.systemInstruction,
607	        lifecycleHandle: { id: row.id },
608	      });
609	      return { name: row.providerResourceName, lifecycleHandle: { id: row.id } };
610	    } catch (err) {
611	      await recordCacheTermination({
612	        db,
613	        handle: { id: row.id },
614	        status: 'orphaned',
615	        reason:
616	          'persisted Vertex cache lookup failed before reuse: ' +
617	          (err instanceof Error ? err.message : String(err)),
618	      });
619	      return null;
620	    }
621	  }
622	
623	  private async cleanupExpiredExplicitCaches(): Promise<void> {
624	    const now = Date.now();
625	    const expired = [...this.explicitCacheByKey.entries()].filter(([, entry]) => entry.expiresAtMs <= now);
626	    if (expired.length === 0) return;
627	    for (const [key, entry] of expired) {
628	      this.explicitCacheByKey.delete(key);
629	      try {
630	        await this.client.caches.delete({ name: entry.name });
631	        await this.cleanupUploadedGcsObject(entry.lifecycleHandle);
632	        if (entry.lifecycleHandle) {
633	          await recordCacheTermination({
634	            db: getDirectDb(),
635	            handle: entry.lifecycleHandle,
636	            status: 'expired',
637	            reason: 'local explicit-cache TTL elapsed; provider cache deleted',
638	          });
639	        }
640	      } catch {
641	        if (entry.lifecycleHandle) {
642	          await recordCacheTermination({
643	            db: getDirectDb(),
644	            handle: entry.lifecycleHandle,
645	            status: 'failed',
646	            reason: 'local explicit-cache TTL elapsed; provider cache delete failed',
647	          });
648	        }
649	      }
650	    }
651	  }
652	
653	  private async cleanupExpiredPersistentCaches(): Promise<void> {
654	    const db = getDirectDb();
655	    const expiredRows = await db
656	      .select({
657	        id: providerCachedContent.id,
658	        providerResourceName: providerCachedContent.providerResourceName,
659	      })
660	      .from(providerCachedContent)
661	      .where(
662	        and(
663	          eq(providerCachedContent.provider, 'vertex'),
664	          eq(providerCachedContent.status, 'active'),
665	          lte(providerCachedContent.hardExpirationAt, new Date()),
666	        ),
667	      )
668	      .orderBy(providerCachedContent.hardExpirationAt)
669	      .limit(10);
670	
671	    for (const row of expiredRows) {
672	      try {
673	        if (row.providerResourceName) {
674	          await this.client.caches.delete({ name: row.providerResourceName });
675	        }
676	        await this.cleanupUploadedGcsObject({ id: row.id });
677	        await recordCacheTermination({
678	          db,
679	          handle: { id: row.id },
680	          status: 'expired',
681	          reason: 'hard expiration elapsed; cache lifecycle sweeper retired provider cache',
682	        });
683	      } catch {
684	        await recordCacheTermination({
685	          db,
686	          handle: { id: row.id },
687	          status: 'failed',
688	          reason: 'hard expiration elapsed; provider cache delete failed during sweeper cleanup',
689	        });
690	      }
691	    }
692	  }
693	
694	  private async recordSuccessfulExplicitCacheReuse(
695	    explicitCache:
696	      | {
697	          lifecycleHandle?: CacheLifecycleHandle;
698	        }
699	      | null,
700	  ): Promise<void> {
701	    if (!explicitCache?.lifecycleHandle) return;
702	    await recordCacheReuse(getDirectDb(), explicitCache.lifecycleHandle);
703	  }
704	
705	  private async cleanupUploadedGcsObject(
706	    lifecycleHandle: CacheLifecycleHandle | undefined,
707	  ): Promise<void> {
708	    if (!lifecycleHandle) return;
709	    const db = getDirectDb();
710	    const [row] = await db
711	      .select({ providerMetadataJson: providerCachedContent.providerMetadataJson })
712	      .from(providerCachedContent)
713	      .where(eq(providerCachedContent.id, lifecycleHandle.id))
714	      .limit(1);
715	    const metadata = row?.providerMetadataJson as
716	      | { uploadedGcsUri?: string; uploadedObjectName?: string }
717	      | undefined;
718	    const objectName = metadata?.uploadedObjectName;
719	    const bucketName = process.env.GOOGLE_VERTEX_CONTEXT_CACHE_GCS_BUCKET;
720	    if (!objectName || !bucketName) return;
721	    try {
722	      await this.getStorageClient().bucket(bucketName).file(objectName).delete({ ignoreNotFound: true });
723	    } catch {
724	      // Best-effort cleanup. Cache lifecycle status still reflects the cache resource teardown result.
725	    }
726	  }
727	
728	  /**
729	   * Normalize Gemini usage into OracleUsage.
730	   *   - promptTokenCount        -> inputTokens
731	   *   - candidatesTokenCount    -> outputTokens
732	   *   - cachedContentTokenCount -> cachedInputTokens
733	   *   - thoughtsTokenCount      -> reasoningTokens (Gemini 2.5+ thinking)
734	   */
735	  private normalizeUsage(
736	    response: GenerateContentResponse,
737	    latencyMs: number,
738	  ): OracleUsage {
739	    const u = response.usageMetadata ?? {};
740	    return {
741	      inputTokens: u.promptTokenCount,
742	      outputTokens: u.candidatesTokenCount,
743	      cachedInputTokens: u.cachedContentTokenCount,
744	      reasoningTokens: u.thoughtsTokenCount,
745	      latencyMs,
746	      providerRequestId: response.responseId,
747	      rawUsageJson: u,
748	    };
749	  }
750	
751	  // ─── Batch API (Vertex Batch Prediction with GCS-backed I/O) ──────────────
752	  //
753	  // Input/output runs through GCS — Vertex doesn't accept inline batch bodies
754	  // for Gemini. Requires GOOGLE_VERTEX_BATCH_GCS_BUCKET to be set with the
755	  // service account having Storage Object Admin on it. See docs/configuration.md.
756	  //
757	  // Vertex batch output preserves input ORDER but doesn't echo a user-supplied
758	  // request ID. The adapter records customIds in submission order and pairs
759	  // them with output lines at retrieve time via providerMetadata.
760	
761	  /**
762	   * Submit a batch of generateContent requests via Vertex Batch Prediction.
763	   * Writes a JSONL input file to `gs://$BUCKET/oracle-batch-<uuid>/input.jsonl`,
764	   * targets `gs://$BUCKET/oracle-batch-<uuid>/output/` for results, and
765	   * returns the BatchJob resource name as providerBatchId.
766	   *
767	   * providerMetadata: { inputGcsUri, outputGcsPrefix, customIdsInOrder }
768	   */
769	  async submitBatch(args: SubmitBatchArgs): Promise<SubmitBatchResult> {
770	    const { route, requests, jsonSchema } = args;
771	    const bucketName = process.env.GOOGLE_VERTEX_BATCH_GCS_BUCKET;
772	    if (!bucketName) {
773	      throw new Error(
774	        'VertexGeminiAdapter.submitBatch: GOOGLE_VERTEX_BATCH_GCS_BUCKET is not set. ' +
775	          'Vertex Batch Prediction needs a GCS bucket for JSONL input/output. ' +
776	          'See docs/configuration.md.',
777	      );
778	    }
779	    const prefixOverride = process.env.GOOGLE_VERTEX_BATCH_GCS_PREFIX?.trim();
780	    const folderId = `oracle-batch-${randomUUID()}`;
781	    const objectPrefix = prefixOverride ? `${prefixOverride}/${folderId}` : folderId;
782	    const inputObjectName = `${objectPrefix}/input.jsonl`;
783	    const outputObjectPrefix = `${objectPrefix}/output/`;
784	
785	    const customIdsInOrder: string[] = [];
786	    const lines: string[] = [];
787	    for (const req of requests) {
788	      customIdsInOrder.push(req.customId);
789	      const { systemPrompt, userMessage } = flattenPlan(req.plan);
790	      const contents: Content[] = [{
791	        role: 'user',
792	        parts: [{ text: userMessage }],
793	      }];
794	      const generationConfig: Record<string, unknown> = {
795	        temperature: jsonSchema ? 0.1 : undefined,
796	      };
797	      if (jsonSchema) {
798	        generationConfig.responseMimeType = 'application/json';
799	        generationConfig.responseJsonSchema = jsonSchema;
800	      }
801	      const thinkingCfg = vertexThinkingConfig(route.reasoningEffort);
802	      if ('thinkingConfig' in thinkingCfg) {
803	        Object.assign(generationConfig, thinkingCfg);
804	      }
805	      for (const k of Object.keys(generationConfig)) {
806	        if (generationConfig[k] === undefined) delete generationConfig[k];
807	      }
808	
809	      const requestBody: Record<string, unknown> = { contents };
810	      if (systemPrompt) {
811	        requestBody.systemInstruction = { parts: [{ text: systemPrompt }] };
812	      }
813	      if (Object.keys(generationConfig).length > 0) {
814	        requestBody.generationConfig = generationConfig;
815	      }
816	      lines.push(JSON.stringify({ request: requestBody }));
817	    }
818	    const jsonl = lines.join('\n') + '\n';
819	
820	    const storage = new Storage();
821	    const bucket = storage.bucket(bucketName);
822	    await bucket.file(inputObjectName).save(Buffer.from(jsonl, 'utf-8'), {
823	      contentType: 'application/jsonl',
824	      resumable: false,
825	    });
826	
827	    const inputGcsUri = `gs://${bucketName}/${inputObjectName}`;
828	    const outputGcsPrefix = `gs://${bucketName}/${outputObjectPrefix}`;
829	
830	    const batch = await this.client.batches.create({
831	      model: route.modelId,
832	      src: { format: 'jsonl', gcsUri: [inputGcsUri] },
833	      config: {
834	        dest: { format: 'jsonl', gcsUri: outputGcsPrefix },
835	        displayName: folderId,
836	      },
837	    });
838	
839	    const providerBatchId = batch.name;
840	    if (!providerBatchId) {
841	      throw new Error('VertexGeminiAdapter.submitBatch: batch.name missing from response');
842	    }
843	
844	    return {
845	      providerBatchId,
846	      providerMetadata: {
847	        inputGcsUri,
848	        outputGcsPrefix,
849	        customIdsInOrder,
850	        bucketName,
851	        outputObjectPrefix,
852	      },
853	    };
854	  }
855	
856	  /**
857	   * Poll Vertex batch status. When the JobState reaches SUCCEEDED, list the
858	   * prediction output objects in GCS (`predictions*.jsonl` — Vertex shards
859	   * large outputs), concatenate them in order, and pair each line with the
860	   * customId at the same index in providerMetadata.customIdsInOrder.
861	   */
862	  async retrieveBatch(args: RetrieveBatchArgs): Promise<RetrieveBatchResult> {
863	    const { providerBatchId, providerMetadata } = args;
864	    const batch = await this.client.batches.get({ name: providerBatchId });
865	    const status = mapVertexBatchStatus(batch.state ?? '');
866	
867	    if (status === 'in_progress' || status === 'submitted') {
868	      return {
869	        status,
870	        requestCount: undefined,
871	        completedCount: undefined,
872	        failedCount: undefined,
873	      };
874	    }
875	
876	    if (status !== 'completed') {
877	      // failed / expired / canceled
878	      return {
879	        status,
880	        error: batch.error?.message ?? `state=${batch.state}`,
881	      };
882	    }
883	
884	    const bucketName = providerMetadata.bucketName as string | undefined;
885	    const outputObjectPrefix = providerMetadata.outputObjectPrefix as string | undefined;
886	    const customIdsInOrder = providerMetadata.customIdsInOrder as string[] | undefined;
887	    if (!bucketName || !outputObjectPrefix || !customIdsInOrder) {
888	      return {
889	        status: 'failed',
890	        error: 'providerMetadata missing bucketName/outputObjectPrefix/customIdsInOrder',
891	      };
892	    }
893	
894	    // List output files. Vertex writes them as predictions-XXXXX-of-YYYYY.jsonl
895	    // under outputObjectPrefix, sometimes inside a deeper subdirectory it
896	    // generates for the job. Filter for *.jsonl and sort lexically so shards
897	    // land in their numbered order.
898	    const storage = new Storage();
899	    const bucket = storage.bucket(bucketName);
900	    const [files] = await bucket.getFiles({ prefix: outputObjectPrefix });
901	    const predictionFiles = files
902	      .filter((f) => f.name.endsWith('.jsonl') && f.name.includes('prediction'))
903	      .sort((a, b) => a.name.localeCompare(b.name));
904	
905	    if (predictionFiles.length === 0) {
906	      return { status: 'failed', error: `no prediction files under gs://${bucketName}/${outputObjectPrefix}` };
907	    }
908	
909	    const results: BatchResultItem[] = [];
910	    let index = 0;
911	    let succeeded = 0;
912	    let failed = 0;
913	    for (const file of predictionFiles) {
914	      const [buf] = await file.download();
915	      const text = buf.toString('utf-8');
916	      for (const rawLine of text.split('\n')) {
917	        if (!rawLine.trim()) continue;
918	        const customId = customIdsInOrder[index] ?? `unknown-${index}`;
919	        index++;
920	        let parsed: {
921	          status?: string;
922	          request?: unknown;
923	          response?: GenerateContentResponse;
924	        };
925	        try {
926	          parsed = JSON.parse(rawLine);
927	        } catch {
928	          results.push({ customId, success: false, error: 'malformed output line' });
929	          failed++;
930	          continue;
931	        }
932	
933	        // Vertex marks per-line errors by populating `status` with a non-empty
934	        // error string. SUCCEEDED lines have an empty/absent status.
935	        if (parsed.status && parsed.status !== '') {
936	          results.push({ customId, success: false, error: parsed.status });
937	          failed++;
938	          continue;
939	        }
940	
941	        if (!parsed.response) {
942	          results.push({ customId, success: false, error: 'no response in output line' });
943	          failed++;
944	          continue;
945	        }
946	
947	        const response = parsed.response as GenerateContentResponse;
948	        const textOut = extractTextFromGeminiResponse(response);
949	        let output: unknown;
950	        let outText: string | undefined;
951	        try {
952	          output = JSON.parse(textOut);
953	        } catch {
954	          outText = textOut;
955	        }
956	        results.push({
957	          customId,
958	          success: true,
959	          output,
960	          text: outText,
961	          usage: this.normalizeUsage(response, 0),
962	        });
963	        succeeded++;
964	      }
965	    }
966	
967	    return {
968	      status: 'completed',
969	      results,
970	      requestCount: customIdsInOrder.length,
971	      completedCount: succeeded,
972	      failedCount: failed,
973	    };
974	  }
975	}
976	
977	// ─── Shared helpers (also used by anthropic + openai adapters) ──────────────
978	
979	/**
980	 * Flatten the OraclePromptPlan into a (systemPrompt, userMessage) pair.
981	 * Stable blocks become the system prompt; semi-stable / retrieved / dynamic
982	 * blocks concatenate into the user message in order. Preserves cacheable-
983	 * prefix ordering so provider-native cache machinery actually hits.
984	 */
985	export function flattenPlan(plan: OraclePromptPlan): {
986	  systemPrompt: string;
987	  userMessage: string;
988	} {
989	  const { systemPrompt, prefixContext, dynamicInput } = splitPlanForCaching(plan);
990	  return {
991	    systemPrompt,
992	    userMessage: [prefixContext, dynamicInput].filter(Boolean).join('\n\n'),
993	  };
994	}
995	
996	/**
997	 * Convert a Zod schema (or any unknown — we duck-type) to standard JSON
998	 * Schema 2020-12. Falls back to assuming the input is already JSON Schema if
999	 * it doesn't look like a Zod object.
1000	 */
1001	export function zodToJsonSchema(schema: unknown): unknown {
1002	  const s = schema as { _def?: unknown };
1003	  if (s && typeof s === 'object' && '_def' in s) {
1004	    return z.toJSONSchema(schema as ZodTypeAny);
1005	  }
1006	  return schema;
1007	}
1008	
1009	/**
1010	 * Best-effort Zod runtime validation. Returns the validated value on success,
1011	 * or null if the input doesn't look like a Zod schema (so the caller can fall
1012	 * back to the raw parsed JSON). Throws on Zod validation failure — the caller
1013	 * decides what to do.
1014	 */
1015	export function tryZodParse<T>(schema: unknown, value: unknown): T | null {
1016	  const s = schema as { safeParse?: (v: unknown) => { success: boolean; data: T; error: unknown } };
1017	  if (s && typeof s === 'object' && typeof s.safeParse === 'function') {
1018	    const result = s.safeParse(value);
1019	    if (!result.success) return null;
1020	    return result.data;
1021	  }
1022	  return null;
1023	}
1024	
1025	export function parseJsonOrRaw(text: string): unknown {
1026	  try {
1027	    return JSON.parse(text);
1028	  } catch {
1029	    return text;
1030	  }
1031	}
1032	
1033	/**
1034	 * Translate unified ReasoningEffort to Vertex Gemini 2.5+'s thinkingConfig.
1035	 * Returns an object you can spread into the request `config`.
1036	 *
1037	 * Budgets (Gemini 2.5 Pro/Flash):
1038	 *   off    → thinkingBudget: 0  (disables thinking)
1039	 *   low    → 1024
1040	 *   medium → 8192
1041	 *   high   → 24576 (Flash hard cap; Pro accepts up to 32768)
1042	 *
1043	 * Models without thinking support (1.x family) ignore the param silently.
1044	 */
1045	function vertexThinkingConfig(effort: ReasoningEffort | undefined):
1046	  | { thinkingConfig: { thinkingBudget: number } }
1047	  | Record<string, never> {
1048	  if (!effort) return {};
1049	  const budget =
1050	    effort === 'off' ? 0
1051	      : effort === 'low' ? 1024
1052	      : effort === 'medium' ? 8192
1053	      : 24576;
1054	  return { thinkingConfig: { thinkingBudget: budget } };
1055	}
1056	
1057	/**
1058	 * Map @google/genai JobState onto our provider-agnostic BatchStatus.
1059	 *
1060	 *   JOB_STATE_QUEUED | _PENDING | _RUNNING | _UPDATING | _PAUSED → 'in_progress'
1061	 *   JOB_STATE_SUCCEEDED                                          → 'completed'
1062	 *   JOB_STATE_PARTIALLY_SUCCEEDED                                → 'completed'
1063	 *   JOB_STATE_FAILED                                             → 'failed'
1064	 *   JOB_STATE_EXPIRED                                            → 'expired'
1065	 *   JOB_STATE_CANCELLING | _CANCELLED                            → 'canceled'
1066	 */
1067	function mapVertexBatchStatus(state: string): BatchStatus {
1068	  switch (state) {
1069	    case 'JOB_STATE_SUCCEEDED':
1070	    case 'JOB_STATE_PARTIALLY_SUCCEEDED':
1071	      return 'completed';
1072	    case 'JOB_STATE_FAILED':
1073	      return 'failed';
1074	    case 'JOB_STATE_EXPIRED':
1075	      return 'expired';
1076	    case 'JOB_STATE_CANCELLING':
1077	    case 'JOB_STATE_CANCELLED':
1078	      return 'canceled';
1079	    case 'JOB_STATE_QUEUED':
1080	    case 'JOB_STATE_PENDING':
1081	    case 'JOB_STATE_RUNNING':
1082	    case 'JOB_STATE_UPDATING':
1083	    case 'JOB_STATE_PAUSED':
1084	      return 'in_progress';
1085	    default:
1086	      // Unknown / undocumented → assume still running so the drain task polls again
1087	      return 'in_progress';
1088	  }
1089	}
1090	
1091	/**
1092	 * Pull the text from a GenerateContentResponse. The synchronous adapter relies
1093	 * on `response.text` (a getter), but offline-deserialized response objects
1094	 * from the batch output JSONL don't carry the getter — they're plain data.
1095	 * Walk candidates[0].content.parts[] and concatenate the text parts.
1096	 */
1097	function extractTextFromGeminiResponse(response: GenerateContentResponse): string {
1098	  // Use the SDK getter if it's present (won't be after JSON.parse).
1099	  const direct = (response as { text?: string }).text;
1100	  if (typeof direct === 'string' && direct.length > 0) return direct;
1101	  const candidate = response.candidates?.[0];
1102	  const parts = candidate?.content?.parts ?? [];
1103	  const chunks: string[] = [];
1104	  for (const part of parts) {
1105	    const partText = (part as { text?: string }).text;
1106	    if (typeof partText === 'string') chunks.push(partText);
1107	  }
1108	  return chunks.join('');
1109	}
