422	  let actualProvider = route.provider;
423	  let actualModelId = route.modelId;
424	  let fellBackFromRouteId: string | undefined;
425	  let fallbackReason: string | undefined;
426	
427	  try {
428	    const messagesWithContext = [
429	      {
430	        role: 'user' as const,
431	        content:
432	          '[Oracle runtime context - not part of the employee chat transcript]\n' +
433	          dynamicContext,
434	      },
435	      ...safeMessages,
436	    ];
437	    const result = await getOracleClient().runText({
438	      taskType: 'interview_chat',
439	      routeId: route.routeId,
440	      promptVersion: ORACLE_SYSTEM_PROMPT_VERSION,
441	      blocks,
442	      observability: {
443	        includedMessageIds: recent.map((m) => m.id),
444	        includedGapIds: openGaps.map((g) => g.id),
445	        includedClaimIds: relevantClaims.map((c) => c.id),
446	      },
447	      providerOptions: {
448	        messages: messagesWithContext,
449	        temperature: 0.4,
450	        cache: {
451	          preferLongLivedCache: true,
452	          // 30 min when caching an attached document for an active chat;
453	          // otherwise the default short interview-context TTL.
454	          cacheTtlSeconds: vertexFileCacheSource ? 30 * 60 : 10 * 60,
455	          expectedReuseCount: 6,
456	          // Activates the adapter's explicit file-cache path (Vertex only).
457	          preferExplicitCache: !!vertexFileCacheSource,
458	          persistProviderCacheRecord: route.provider === 'vertex',
459	          sourceDescription: `channel ${body.channelId} interview context`,
460	          cleanupOwner: 'chat-route',
461	          latestPlannedReuseStep: 'interview_chat',
462	          vertexFileCacheSource,
463	          sessionCacheKey:
464	            qwenSessionKey ?? undefined,
465	          previousResponseId:
466	            route.provider === 'qwen'
467	              ? previousQwenSession[0]?.modelId === route.modelId
468	                ? previousQwenSession[0]?.latestResponseId
469	                : undefined
470	              : undefined,
471	        },
472	      },
473	    });
474	    oracleText = result.text;
475	    inputTokens = result.usage.inputTokens;
476	    outputTokens = result.usage.outputTokens;
477	    cachedInputTokens = result.usage.cachedInputTokens;
478	    usageRaw = result.usage.rawUsageJson;
479	    providerRequestId = result.usage.providerRequestId;
480	    actualRouteId = result.routeId ?? route.routeId;
481	    actualProvider = (result.provider as typeof route.provider | undefined) ?? route.provider;
482	    actualModelId = result.modelId ?? route.modelId;
483	    fellBackFromRouteId = result.fellBackFromRouteId;
484	    fallbackReason = result.fallbackReason;
485	    success = true;
486	  } catch (err) {
487	    modelError = err instanceof Error ? err.message : String(err);
488	    console.error('[chat] model error', err);
489	  } finally {
490	    // The GCS object is reaped by the adapter's cache-TTL sweeper; we only own
491	    // the local temp file. Best-effort cleanup.
492	    if (cachedTempPath) {
493	      await unlink(cachedTempPath).catch(() => undefined);
494	    }
495	  }
496	
497	  // ── 9. Log model_runs + model_run_usage_details + back-link pack ───
498	  const [modelRun] = await db
499	    .insert(modelRuns)
500	    .values({
501	      taskType: 'interview_chat',
502	      model: actualModelId,
503	      provider: actualProvider,
504	      promptVersion: ORACLE_SYSTEM_PROMPT_VERSION,
505	      inputHash: plan.metadata.stablePrefixHash,
506	      inputTokens: inputTokens ?? null,
507	      outputTokens: outputTokens ?? null,
508	      latencyMs: Date.now() - startedAt,
509	      success,
510	      error: modelError ?? null,
511	    })
512	    .returning({ id: modelRuns.id });
513	
514	  if (modelRun) {
515	    await db.insert(modelRunUsageDetails).values({
516	      modelRunId: modelRun.id,
517	      contextPackId: contextPack.id,
518	      routeId: actualRouteId,
519	      inputTokens: inputTokens ?? null,
520	      cachedInputTokens: cachedInputTokens ?? null,
521	      outputTokens: outputTokens ?? null,
522	      providerRequestId: providerRequestId ?? null,
523	      rawUsageJson: usageRaw ?? null,
524	      fellBackFromRouteId: fellBackFromRouteId ?? null,
525	      fallbackReason: fallbackReason ?? null,
526	    });
527	    await db
528	      .update(oracleContextPacks)
529	      .set({ modelRunId: modelRun.id })
530	      .where(eq(oracleContextPacks.id, contextPack.id));
531	
532	    if (actualProvider === 'qwen' && providerRequestId && qwenSessionKey) {
533	      await db
534	        .insert(providerResponseSessions)
535	        .values({
536	          provider: 'qwen',
537	          sessionKey: qwenSessionKey,
538	          scopeKind: 'channel',
539	          scopeId: body.channelId,
540	          modelId: actualModelId,
541	          latestResponseId: providerRequestId,
542	          lastContextPackId: contextPack.id,
543	          lastModelRunId: modelRun.id,
544	          metadataJson: {
545	            routeId: actualRouteId,
546	          },
547	        })
548	        .onConflictDoUpdate({
549	          target: [
550	            providerResponseSessions.provider,
551	            providerResponseSessions.sessionKey,
552	          ],
553	          set: {
554	            modelId: actualModelId,
555	            latestResponseId: providerRequestId,
556	            lastContextPackId: contextPack.id,
557	            lastModelRunId: modelRun.id,
558	            metadataJson: {
559	              routeId: actualRouteId,
560	            },
561	            updatedAt: new Date(),
562	          },
563	        });
564	    }
565	  }
566	
567	  if (!success || !oracleText.trim()) {
568	    return NextResponse.json(
569	      { error: 'model_failed', detail: modelError ?? 'empty response' },
570	      { status: 502 },
571	    );
572	  }
573	
574	  // ── 10. Persist Oracle reply as assistant message ───────────────────
575	  const [inserted] = await db
576	    .insert(messages)
577	    .values({
578	      channelId: body.channelId,
579	      employeeId: null,
580	      role: 'assistant',
581	      content: oracleText.trim(),
582	      extractionStatus: 'skipped',
583	    })
584	    .returning();
585	
586	  return NextResponse.json({
587	    ok: true,
588	    messageId: inserted?.id,
589	    routeId: actualRouteId,
590	    model: actualModelId,
591	    provider: actualProvider,
592	    contextPackId: contextPack.id,
593	    modelRunId: modelRun?.id ?? null,
594	    latencyMs: Date.now() - startedAt,
595	  });
596	}
597	
598	// ─────────────────────────────────────────────────────────────────────────
599	// Helpers
600	// ─────────────────────────────────────────────────────────────────────────
601	
602	/**
603	 * Build the selectedDomains array for the context pack.
604	 * - domain_filtered: return the actual domain IDs.
605	 * - global_fallback / global_explicit: return a single sentinel tag so
606	 *   operators can query: WHERE selected_domains @> ARRAY['_global_fallback'].
607	 */
608	function scopeTag(topDomainHints: string[], scope: RetrievalPlanSearchScope): string[] {
609	  if (topDomainHints.length > 0) return topDomainHints;
610	  return [`_${scope}`]; // '_global_fallback' or '_global_explicit'
611	}
612	
613	async function resolveInterviewRoute(db: OracleDb): Promise<OracleModelRoute> {
614	  // resolveRouteFromSettings handles catalog routeIds, OpenRouter "provider/model"
615	  // IDs from the pool picker, AND attaches the admin's saved reasoning effort.
616	  const resolved = await resolveRouteFromSettings(db, 'interview');
617	  if (resolved) return resolved;
618	  const fb = getOracleRoute(FALLBACK_ROUTE_ID);
619	  if (!fb) {
620	    throw new Error(
621	      `[chat] default_interview_route unset/unresolvable and fallback "${FALLBACK_ROUTE_ID}" missing.`,
622	    );
623	  }
624	  console.warn(`[chat] default_interview_route unset/unresolvable; using fallback "${FALLBACK_ROUTE_ID}".`);
625	  return fb;
626	}
627	
628	/**
629	 * Pick at most ONE document to route through the Vertex GCS file cache: the
630	 * most-recent PDF attachment in the recent-message window. Walks newest→oldest
631	 * so an attachment on the latest turn wins.
632	 */
633	function pickCacheablePdf<T extends { fileType: string }>(
634	  recentMessages: Array<{ id: string }>,
635	  attachmentMap: Map<string, T[]>,
636	): T | null {
637	  for (let i = recentMessages.length - 1; i >= 0; i -= 1) {
638	    const atts = attachmentMap.get(recentMessages[i]!.id) ?? [];
639	    const pdf = atts.find((a) => a.fileType === 'application/pdf');
640	    if (pdf) return pdf;
641	  }
642	  return null;
643	}
644	
645	async function materializeVertexCacheTempFile(buffer: Buffer, fileName: string): Promise<string> {
646	  const safeName = fileName.replace(/[^a-zA-Z0-9._-]/g, '_');
647	  const tempPath = join(tmpdir(), `oracle-chat-vertex-cache-${Date.now()}-${safeName}`);
648	  await writeFile(tempPath, buffer);
649	  return tempPath;
650	}
651	
652	function isVisionCapableRoute(route: OracleModelRoute): boolean {
653	  // Vision detection from the route's flags + a name regex fallback. The
654	  // curated catalog already encodes supportsVision on each route; the
655	  // regex is a defensive belt-and-suspenders in case a catalog entry
656	  // gets misconfigured.
657	  if (route.supportsVision) return true;
658	  return /claude|gpt-4o|gemini|llava|pixtral|qwen.*vl|minicpm/i.test(route.modelId);
659	}
660	
661	function buildContextPackInsert(plan: OraclePromptPlan) {
662	  return {
663	    taskType: plan.taskType,
664	    routeId: plan.routeId,
665	    promptVersion: plan.promptVersion,
666	    schemaVersion: plan.schemaVersion ?? null,
667	    stablePrefixHash: plan.metadata.stablePrefixHash,
668	    semiStableContextHash: plan.metadata.semiStableContextHash ?? null,
669	    retrievedContextHash: plan.metadata.retrievedContextHash ?? null,
670	    dynamicInputHash: plan.metadata.dynamicInputHash,
671	    toolSchemaHash: plan.metadata.toolSchemaHash ?? null,
672	    outputSchemaHash: plan.metadata.outputSchemaHash ?? null,
673	    blocksJson: plan.blocks.map((b) => ({
674	      id: b.id,
675	      label: b.label,
676	      kind: b.kind,
677	      hash: b.hash,
678	      tokenEstimate: b.tokenEstimate ?? null,
679	      cacheEligible: b.cacheEligible,
680	      reasonIncluded: b.reasonIncluded,
681	    })),
682	    retrievalPlanId: plan.metadata.retrievalPlanId ?? null,
683	    selectedDomains: plan.metadata.selectedDomains ?? null,
684	    selectedSourceTypes: plan.metadata.selectedSourceTypes ?? null,
685	    selectedProcessStages: plan.metadata.selectedProcessStages ?? null,
686	    selectedEntityIds: plan.metadata.selectedEntityIds ?? null,
687	    includedMessageIds: plan.metadata.includedMessageIds ?? null,
688	    includedDocumentChunkIds: plan.metadata.includedDocumentChunkIds ?? null,
689	    includedClaimIds: plan.metadata.includedClaimIds ?? null,
690	    includedGapIds: plan.metadata.includedGapIds ?? null,
691	    includedContradictionIds: plan.metadata.includedContradictionIds ?? null,
692	  };
693	}
